// Two jobs:
//
// 1. Deduplicates kv_namespaces entries in wrangler.json files generated by
//    @astrojs/cloudflare. The adapter's vite plugin incorrectly includes
//    user-defined KV bindings twice when kv_namespaces is in wrangler.jsonc
//    (bug in @cloudflare/vite-plugin v1.36).
//
// 2. Writes a root-level wrangler.json (gitignored) with absolute paths for
//    Cloudflare Pages CI. Pages CI reads this after running `npm run build`,
//    so `dist/server/entry.mjs` exists by the time it's referenced.
//    Local wrangler dev/deploy redirect to dist/server/wrangler.json instead.

import { readFileSync, writeFileSync, existsSync } from 'fs';

function dedup(path) {
  if (!existsSync(path)) return null;
  const config = JSON.parse(readFileSync(path, 'utf8'));
  if (!Array.isArray(config.kv_namespaces)) return config;
  const seen = new Set();
  const before = config.kv_namespaces.length;
  config.kv_namespaces = config.kv_namespaces.filter(kv => {
    if (seen.has(kv.binding)) return false;
    seen.add(kv.binding);
    return true;
  });
  if (config.kv_namespaces.length !== before) {
    writeFileSync(path, JSON.stringify(config, null, '\t'));
    console.log(`[fix-wrangler] Removed ${before - config.kv_namespaces.length} duplicate(s) from ${path}`);
  }
  return config;
}

const serverConfig = dedup('dist/server/wrangler.json');
dedup('dist/server/.prerender/wrangler.json');

// Generate root wrangler.json for Cloudflare Pages CI.
// Pages reads this after the build, so dist/server/entry.mjs exists.
// Only include fields CF needs — strip internal wrangler metadata fields
// (configPath, userConfigPath, etc.) that contain local absolute paths
// and would cause CI to fail when those paths don't exist.
if (serverConfig) {
  const pagesConfig = {
    name: 'tiff-epm',
    compatibility_date: serverConfig.compatibility_date,
    compatibility_flags: serverConfig.compatibility_flags,
    main: 'dist/server/entry.mjs',
    assets: {
      directory: './dist/client',
      binding: 'ASSETS',
    },
    kv_namespaces: serverConfig.kv_namespaces,
    observability: serverConfig.observability,
  };
  writeFileSync('wrangler.json', JSON.stringify(pagesConfig, null, '\t'));
  console.log('[fix-wrangler] Wrote root wrangler.json for Cloudflare Pages CI');
}
